#include<bits/stdc++.h>
using namespace std;
const int N = 2e5+5;
long long T,n,a[N],dp[N],pre[N*5],sum[N];
long long read(){
    long long su=0,pp=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){
        if(ch=='-')pp=-1;
        ch=getchar();
    }
    while(ch>='0'&&ch<='9'){
        su=su*10+ch-'0';
        ch=getchar();
    }
    return su*pp;
}
int main(){
    //freopen("color.in","r",stdin);
    //freopen("color.out","w",stdout);
    T=read();
    while(T--){
        n=read();
        for(int i=1;i<=n;i++)a[i]=read();
        memset(dp,0,sizeof(dp));
        memset(pre,0,sizeof(pre));
        memset(sum,0,sizeof(sum));
        for(int i=1;i<=n;i++)sum[i]=sum[i-1]+(a[i]==a[i-1]?a[i]:0);
        for(int i=1;i<=n;i++){
            int j=pre[a[i]];
            pre[a[i]]=i;
            if(!j)dp[i]=dp[i-1];
            else if(j==i-1)dp[i]=dp[i-1]+a[i];
            else dp[i]=max(dp[i-1],dp[j+1]+sum[i-1]-sum[j+1]+a[i]);
        }
        cout<<dp[n]<<"\n";
    }
    return 0;
}
